/* ============================================================
   empty-state.css — สถานะ "ไม่มีข้อมูล" ใช้ในตาราง/รายการทุกหน้า
   ============================================================ */

.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: var(--space-7) var(--space-5);
  color: var(--color-text-muted);
}

.empty-state-icon {
  width: 72px;
  height: 72px;
  border-radius: 50%;
  background: var(--color-bg-canvas);
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: var(--space-4);
  font-size: 28px;
  color: var(--color-text-faint);
}

.empty-state-title {
  font-size: var(--fs-h3);
  font-weight: 600;
  color: var(--color-text);
  margin-bottom: var(--space-1);
}

.empty-state-message {
  font-size: var(--fs-small);
  max-width: 320px;
  margin-bottom: var(--space-4);
}

.empty-state .btn {
  margin-top: var(--space-1);
}
